import api from "./api";
import { getAuthHeaders } from "./authService";

// Xử lý thanh toán
export const processPayment = (payload) => {
  return api.post("/users/payments", payload, {
    headers: getAuthHeaders(),
  });
};

// Lấy danh sách thanh toán của người dùng
export const getMyPayments = () => {
  return api.get("/users/payments", {
    headers: getAuthHeaders(),
  });
};

// Lấy chi tiết thanh toán
export const getPaymentDetail = (id) => {
  return api.get(`/users/payments/${id}`, {
    headers: getAuthHeaders(),
  });
};
